import{_ as n,o as l,c as i,am as s,j as a,a as e,bN as r}from"./chunks/framework.yzuB8YhR.js";const f=JSON.parse('{"title":"FastAPI 安装与环境配置","description":"","frontmatter":{},"headers":[],"relativePath":"编程/Python/FastAPI/02.安装.md","filePath":"编程/Python/FastAPI/02.安装.md","lastUpdated":1776923458000}'),p={name:"编程/Python/FastAPI/02.安装.md"};function d(o,t,h,c,b,g){return l(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="fastapi-安装与环境配置" tabindex="-1">FastAPI 安装与环境配置 <a class="header-anchor" href="#fastapi-安装与环境配置" aria-label="Permalink to “FastAPI 安装与环境配置”">​</a></h1><p>FastAPI 依赖 Python 3.8 及更高版本。本节介绍如何安装 FastAPI 以及配置开发环境。</p><hr><h2 id="检查-python-版本" tabindex="-1">检查 Python 版本 <a class="header-anchor" href="#检查-python-版本" aria-label="Permalink to “检查 Python 版本”">​</a></h2><p>在安装 FastAPI 之前，先确认你的 Python 版本：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ python --version</span></span>
<span class="line"><span>Python 3.11.0</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 或者</span></span>
<span class="line"><span>$ python3 --version</span></span>
<span class="line"><span>Python 3.11.0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>如果你的 Python 版本低于 3.8，请先升级 Python。</p><hr><h2 id="创建虚拟环境" tabindex="-1">创建虚拟环境 <a class="header-anchor" href="#创建虚拟环境" aria-label="Permalink to “创建虚拟环境”">​</a></h2><p>推荐在虚拟环境中安装 FastAPI，避免与系统 Python 包产生冲突：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 创建虚拟环境</span></span>
<span class="line"><span>$ python -m venv venv</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 激活虚拟环境（macOS/Linux）</span></span>
<span class="line"><span>$ source venv/bin/activate</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 激活虚拟环境（Windows）</span></span>
<span class="line"><span>$ venv\\Scripts\\activate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><blockquote><p>虚拟环境是 Python 开发的最佳实践。每个项目使用独立的虚拟环境，可以避免不同项目之间的依赖冲突。</p></blockquote><hr><h2 id="安装-fastapi" tabindex="-1">安装 FastAPI <a class="header-anchor" href="#安装-fastapi" aria-label="Permalink to “安装 FastAPI”">​</a></h2><p>使用 pip 安装 FastAPI：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ pip install fastapi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这条命令只安装 FastAPI 核心包。如果你需要一次性安装 FastAPI 及其所有可选依赖，可以使用：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ pip install &quot;fastapi[all]&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>fastapi[all]</code> 会安装以下组件：</p><table tabindex="0"><thead><tr><th style="text-align:left;">包名</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;"><code>uvicorn[standard]</code></td><td style="text-align:left;">ASGI 服务器，用于运行 FastAPI 应用</td></tr><tr><td style="text-align:left;"><code>python-multipart</code></td><td style="text-align:left;">表单数据和文件上传支持</td></tr><tr><td style="text-align:left;"><code>jinja2</code></td><td style="text-align:left;">HTML 模板引擎</td></tr><tr><td style="text-align:left;"><code>python-jose[cryptography]</code></td><td style="text-align:left;">JWT 令牌支持</td></tr><tr><td style="text-align:left;"><code>passlib[bcrypt]</code></td><td style="text-align:left;">密码哈希与加密</td></tr><tr><td style="text-align:left;"><code>python-dotenv</code></td><td style="text-align:left;">环境变量管理</td></tr></tbody></table><hr><h2 id="安装-uvicorn" tabindex="-1">安装 Uvicorn <a class="header-anchor" href="#安装-uvicorn" aria-label="Permalink to “安装 Uvicorn”">​</a></h2><p>FastAPI 是一个 ASGI 框架，需要一个 ASGI 服务器来运行。最常用的是 Uvicorn：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ pip install &quot;uvicorn[standard]&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>[standard]</code> 会安装 uvloop（高性能事件循环）和 httptools（高性能 HTTP 解析器），显著提升性能。</p><blockquote><p>ASGI（Asynchronous Server Gateway Interface）是 Python 异步 Web 服务器与应用程序之间的标准接口，是 WSGI 的异步版本。传统框架如 Flask 使用 WSGI（同步），而 FastAPI 使用 ASGI（异步），能够更高效地处理并发请求。</p></blockquote><hr><h2 id="运行第一个-fastapi-应用" tabindex="-1">运行第一个 FastAPI 应用 <a class="header-anchor" href="#运行第一个-fastapi-应用" aria-label="Permalink to “运行第一个 FastAPI 应用”">​</a></h2><p>安装完成后，创建一个名为 <strong>main.py</strong> 的文件：</p><h2 id="实例" tabindex="-1">实例 <a class="header-anchor" href="#实例" aria-label="Permalink to “实例”">​</a></h2><p><strong>from</strong> fastapi <strong>import</strong> FastAPI</p><p># 创建 FastAPI 应用实例 app = FastAPI()</p>`,32),a("p",{"message:":"",HelloWorld:""},[e('# 定义根路径的 GET 路由 @app.get("/") async '),a("strong",null,"def"),e(" root(): "),a("strong",null,"return")],-1),s(`<p>在命令行中启动应用：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$ uvicorn main:app --reload</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>参数说明：</p><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>main:app</code></td><td style="text-align:left;"><code>main</code> 指文件名 main.py，<code>app</code> 指文件中创建的 FastAPI 实例变量名</td></tr><tr><td style="text-align:left;"><code>--reload</code></td><td style="text-align:left;">开发模式，代码修改后自动重载服务器（仅用于开发环境）</td></tr></tbody></table><p>启动成功后，终端会显示：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>INFO:     Uvicorn running on http://127.0.0.1:8000 (Press CTRL+C to quit)</span></span>
<span class="line"><span>INFO:     Started reloader process</span></span>
<span class="line"><span>INFO:     Started server process</span></span>
<span class="line"><span>INFO:     Waiting for application startup.</span></span>
<span class="line"><span>INFO:     Application startup complete.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>打开浏览器访问 <strong><a href="http://127.0.0.1:8000" target="_blank" rel="noreferrer">http://127.0.0.1:8000</a></strong>，你将看到如下 JSON 响应：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{&quot;message&quot;: &quot;Hello World&quot;}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><img src="`+r+`" alt="img"></p><p>同时，FastAPI 自动生成了交互式 API 文档：</p><table tabindex="0"><thead><tr><th style="text-align:left;">地址</th><th style="text-align:left;">文档类型</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="http://127.0.0.1:8000/docs" target="_blank" rel="noreferrer">http://127.0.0.1:8000/docs</a></strong></td><td style="text-align:left;">Swagger UI</td><td style="text-align:left;">可交互测试 API 的文档界面</td></tr><tr><td style="text-align:left;"><strong><a href="http://127.0.0.1:8000/redoc" target="_blank" rel="noreferrer">http://127.0.0.1:8000/redoc</a></strong></td><td style="text-align:left;">ReDoc</td><td style="text-align:left;">更注重阅读体验的文档界面</td></tr></tbody></table><hr><h2 id="使用-fastapi-cli" tabindex="-1">使用 FastAPI CLI <a class="header-anchor" href="#使用-fastapi-cli" aria-label="Permalink to “使用 FastAPI CLI”">​</a></h2><p>FastAPI 新版本提供了 <strong>fastapi</strong> 命令行工具，可以更方便地运行应用：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 开发模式（自动重载）</span></span>
<span class="line"><span>$ fastapi dev</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 生产模式</span></span>
<span class="line"><span>$ fastapi run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>fastapi dev</code> 会自动查找项目中的 FastAPI 应用并启动开发服务器，等同于 <code>uvicorn main:app --reload</code>。</p><hr><h2 id="推荐开发工具" tabindex="-1">推荐开发工具 <a class="header-anchor" href="#推荐开发工具" aria-label="Permalink to “推荐开发工具”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VS Code</a></td><td style="text-align:left;">免费、轻量，配合 Python 和 Pylance 插件有极佳的 FastAPI 开发体验</td></tr><tr><td style="text-align:left;"><a href="https://www.jetbrains.com/pycharm/" target="_blank" rel="noreferrer">PyCharm</a></td><td style="text-align:left;">专业 Python IDE，内置 FastAPI 项目模板和强大的调试功能</td></tr><tr><td style="text-align:left;"><a href="https://qoder.com/users/sign-up?referral_code=whhACoCj9WryAtAh2HAqjvE2ppbzwWtz" target="_blank" rel="noreferrer">阿里 Qoder</a></td><td style="text-align:left;">阿里推出的 AI 编程 IDE，基于 VS Code 深度定制</td></tr><tr><td style="text-align:left;"><a href="https://www.trae.cn/?utm_source=advertising&amp;utm_medium=runoob_ug_cpa&amp;utm_term=hw_trae_runoob" target="_blank" rel="noreferrer">字节 Trae</a></td><td style="text-align:left;">字节跳动推出的 AI 驱动开发工具，内置 Python 支持</td></tr></tbody></table><blockquote><p>推荐使用 VS Code + Python 插件，它对 FastAPI 的类型注解和自动补全支持最好，且完全免费。</p></blockquote>`,20)])])}const m=n(p,[["render",d]]);export{f as __pageData,m as default};
